/* Paixão de Cristo de Maracanaú - JavaScript Minificado */
document.addEventListener('DOMContentLoaded',function(){'use strict';initSmoothScrolling();initNavbarBehavior();initFormValidation();initImageLazyLoading();initAccessibilityFeatures();initAnimations();initCounters()});
function initSmoothScrolling(){const links=document.querySelectorAll('a[href^="#"]');links.forEach(link=>{link.addEventListener('click',function(e){const targetId=this.getAttribute('href');if(targetId==='#')return;const targetElement=document.querySelector(targetId);if(targetElement){e.preventDefault();const offsetTop=targetElement.offsetTop-80;window.scrollTo({top:offsetTop,behavior:'smooth'});history.pushState(null,null,targetId);targetElement.focus()}})})}
function initNavbarBehavior(){const navbar=document.querySelector('.navbar');const navbarToggler=document.querySelector('.navbar-toggler');const navbarCollapse=document.querySelector('.navbar-collapse');window.addEventListener('scroll',function(){if(window.scrollY>50){navbar.classList.add('navbar-scrolled')}else{navbar.classList.remove('navbar-scrolled')}});const navLinks=document.querySelectorAll('.navbar-nav .nav-link');navLinks.forEach(link=>{link.addEventListener('click',function(){if(navbarCollapse.classList.contains('show')){navbarToggler.click()}})});document.addEventListener('click',function(e){const isClickInsideNav=navbar.contains(e.target);if(!isClickInsideNav&&navbarCollapse.classList.contains('show')){navbarToggler.click()}})}
function initFormValidation(){const forms=document.querySelectorAll('form');forms.forEach(form=>{form.addEventListener('submit',function(e){if(!validateForm(this)){e.preventDefault();return false}})})}
function validateForm(form){let isValid=true;const requiredFields=form.querySelectorAll('[required]');requiredFields.forEach(field=>{if(!field.value.trim()){showFieldError(field,'Este campo é obrigatório');isValid=false}else{clearFieldError(field)}});const emailFields=form.querySelectorAll('input[type="email"]');emailFields.forEach(field=>{if(field.value&&!isValidEmail(field.value)){showFieldError(field,'E-mail inválido');isValid=false}else{clearFieldError(field)}});return isValid}
function isValidEmail(email){const emailRegex=/^[^\s@]+@[^\s@]+\.[^\s@]+$/;return emailRegex.test(email)}
function showFieldError(field,message){clearFieldError(field);field.classList.add('is-invalid');const errorDiv=document.createElement('div');errorDiv.className='invalid-feedback';errorDiv.textContent=message;field.parentNode.appendChild(errorDiv)}
function clearFieldError(field){field.classList.remove('is-invalid');const errorDiv=field.parentNode.querySelector('.invalid-feedback');if(errorDiv){errorDiv.remove()}}
function initImageLazyLoading(){if('IntersectionObserver' in window){const imageObserver=new IntersectionObserver((entries,observer)=>{entries.forEach(entry=>{if(entry.isIntersecting){const img=entry.target;img.src=img.dataset.src;img.classList.remove('lazy');img.classList.add('loaded');observer.unobserve(img)}})},{rootMargin:'50px 0px',threshold:0.01});document.querySelectorAll('img[data-src]').forEach(img=>{imageObserver.observe(img)})}else{document.querySelectorAll('img[data-src]').forEach(img=>{img.src=img.dataset.src;img.classList.remove('lazy');img.classList.add('loaded')})}}
function initAccessibilityFeatures(){const skipLink=document.createElement('a');skipLink.href='#main-content';skipLink.textContent='Pular para o conteúdo principal';skipLink.className='skip-link';document.body.insertBefore(skipLink,document.body.firstChild);document.addEventListener('keydown',function(e){if(e.key==='Tab'){document.body.classList.add('keyboard-navigation')}});document.addEventListener('mousedown',function(){document.body.classList.remove('keyboard-navigation')})}
function initAnimations(){const animatedElements=document.querySelectorAll('.fade-in-up, .fade-in-left, .fade-in-right');if('IntersectionObserver' in window){const animationObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.style.animationPlayState='running';animationObserver.unobserve(entry.target)}})},{threshold:0.1});animatedElements.forEach(el=>{el.style.animationPlayState='paused';animationObserver.observe(el)})}}
function initCounters(){const counters=document.querySelectorAll('.counter');if('IntersectionObserver' in window){const counterObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){animateCounter(entry.target);counterObserver.unobserve(entry.target)}})},{threshold:0.5});counters.forEach(counter=>{counterObserver.observe(counter)})}}
function animateCounter(element){const target=parseInt(element.dataset.target);const duration=2000;const increment=target/(duration/16);let current=0;const timer=setInterval(()=>{current+=increment;element.textContent=Math.floor(current);if(current>=target){element.textContent=target;clearInterval(timer)}},16)}
/* Utilitários */
function debounce(func,wait){let timeout;return function executedFunction(...args){const later=()=>{clearTimeout(timeout);func(...args)};clearTimeout(timeout);timeout=setTimeout(later,wait)}}
function throttle(func,limit){let inThrottle;return function(){const args=arguments;const context=this;if(!inThrottle){func.apply(context,args);inThrottle=true;setTimeout(()=>inThrottle=false,limit)}}}
/* Performance */
const debouncedResize=debounce(()=>{window.dispatchEvent(new Event('optimizedResize'))},250);
window.addEventListener('resize',debouncedResize);
/* Acessibilidade melhorada */
document.addEventListener('keydown',function(e){if(e.key==='Escape'){const modals=document.querySelectorAll('.modal.show');modals.forEach(modal=>{const modalInstance=bootstrap.Modal.getInstance(modal);if(modalInstance){modalInstance.hide()}})}});
/* Smooth scroll para navegadores antigos */
if(!CSS.supports('scroll-behavior','smooth')){const style=document.createElement('style');style.textContent='html{scroll-behavior:smooth}';document.head.appendChild(style)}
